# Organisations at different maturity levels use different weight sets.
# The standard weights can be overridden per scoring cycle.

WEIGHT_PROFILES = {
    "standard": {
        "business_impact": 0.35, "strategic_fit": 0.20,
        "data_readiness": 0.20, "tech_feasibility": 0.15, "change_feasibility": 0.10,
    },
    "data_constrained": {
        # Organisation has immature data platform — data readiness gates everything
        "business_impact": 0.30, "strategic_fit": 0.15,
        "data_readiness": 0.35, "tech_feasibility": 0.10, "change_feasibility": 0.10,
    },
    "regulated_industry": {
        # Risk and change management dominate due to regulatory context
        "business_impact": 0.30, "strategic_fit": 0.20,
        "data_readiness": 0.15, "tech_feasibility": 0.15, "change_feasibility": 0.20,
    },
    "platform_building": {
        # Early-stage programme: prioritise platform-enabling use cases
        "business_impact": 0.20, "strategic_fit": 0.30,
        "data_readiness": 0.20, "tech_feasibility": 0.20, "change_feasibility": 0.10,
    },
}

def score_with_profile(item, profile_name: str = "standard") -> float:
    weights = WEIGHT_PROFILES[profile_name]
    raw = sum(
        getattr(item, dim) * w for dim, w in weights.items()
    )
    return round(raw - RISK_PENALTY[item.risk_level], 3)

# Compare UC-001 across profiles
from types import SimpleNamespace
uc001 = SimpleNamespace(
    business_impact=5, strategic_fit=4, data_readiness=4,
    tech_feasibility=4, change_feasibility=3, risk_level="Low"
)
for profile in WEIGHT_PROFILES:
    print(f"{profile:<25}: {score_with_profile(uc001, profile):.3f}")
# standard                 : 4.150
# data_constrained         : 4.100
# regulated_industry       : 4.000
# platform_building        : 3.900
